class Solution:
    def maxProduct(self, s):
        n = len(s)
        # best[j] over odd palindromes: gather all odd-length palindromic intervals.
        endbest = [1] * n
        startbest = [1] * n
        for c in range(n):
            k = 0
            while c - k >= 0 and c + k < n and s[c - k] == s[c + k]:
                length = 2 * k + 1
                R = c + k
                L = c - k
                if length > endbest[R]:
                    endbest[R] = length
                if length > startbest[L]:
                    startbest[L] = length
                k += 1
        pref = [0] * n
        pref[0] = endbest[0]
        for j in range(1, n):
            pref[j] = max(pref[j - 1], endbest[j])
        suf = [0] * n
        suf[n - 1] = startbest[n - 1]
        for j in range(n - 2, -1, -1):
            suf[j] = max(suf[j + 1], startbest[j])
        ans = 0
        for j in range(n - 1):
            ans = max(ans, pref[j] * suf[j + 1])
        return ans

