class Solution:
    def maxProduct(self, s):
        n = len(s)
        d = [0] * n
        l = 0
        r = -1
        for i in range(n):
            k = 1 if i > r else min(d[l + r - i], r - i + 1)
            while i - k >= 0 and i + k < n and s[i - k] == s[i + k]:
                k += 1
            d[i] = k
            if i + k - 1 > r:
                l = i - k + 1
                r = i + k - 1
        endLen = [1] * n
        startLen = [1] * n
        for i in range(n):
            rad = d[i] - 1
            L = i - rad
            R = i + rad
            length = 2 * rad + 1
            if length > endLen[R]:
                endLen[R] = length
            if length > startLen[L]:
                startLen[L] = length
        for j in range(n - 2, -1, -1):
            if endLen[j + 1] - 2 > endLen[j]:
                endLen[j] = endLen[j + 1] - 2
        for j in range(1, n):
            if startLen[j - 1] - 2 > startLen[j]:
                startLen[j] = startLen[j - 1] - 2
        pref = [0] * n
        pref[0] = endLen[0]
        for j in range(1, n):
            pref[j] = max(pref[j - 1], endLen[j])
        suf = [0] * n
        suf[n - 1] = startLen[n - 1]
        for j in range(n - 2, -1, -1):
            suf[j] = max(suf[j + 1], startLen[j])
        ans = 0
        for j in range(n - 1):
            p = pref[j] * suf[j + 1]
            if p > ans:
                ans = p
        return ans

