var maxProduct = function(s) {
    const n = s.length;
    const d = new Array(n).fill(0);
    let l = 0, r = -1;
    for (let i = 0; i < n; i++) {
        let k = i > r ? 1 : Math.min(d[l + r - i], r - i + 1);
        while (i - k >= 0 && i + k < n && s[i - k] === s[i + k]) k++;
        d[i] = k;
        if (i + k - 1 > r) { l = i - k + 1; r = i + k - 1; }
    }
    const endLen = new Array(n).fill(1);
    const startLen = new Array(n).fill(1);
    for (let i = 0; i < n; i++) {
        const rad = d[i] - 1;
        const L = i - rad, R = i + rad;
        const length = 2 * rad + 1;
        if (length > endLen[R]) endLen[R] = length;
        if (length > startLen[L]) startLen[L] = length;
    }
    for (let j = n - 2; j >= 0; j--) if (endLen[j + 1] - 2 > endLen[j]) endLen[j] = endLen[j + 1] - 2;
    for (let j = 1; j < n; j++) if (startLen[j - 1] - 2 > startLen[j]) startLen[j] = startLen[j - 1] - 2;
    const pref = new Array(n).fill(0);
    pref[0] = endLen[0];
    for (let j = 1; j < n; j++) pref[j] = Math.max(pref[j - 1], endLen[j]);
    const suf = new Array(n).fill(0);
    suf[n - 1] = startLen[n - 1];
    for (let j = n - 2; j >= 0; j--) suf[j] = Math.max(suf[j + 1], startLen[j]);
    let ans = 0;
    for (let j = 0; j < n - 1; j++) {
        const p = pref[j] * suf[j + 1];
        if (p > ans) ans = p;
    }
    return ans;
};
